import { d3_values, defined, mergeJSON } from '../../../utils/zcutils';
import { getAnimationConf, interTween } from '../../../utils/animationutils';
import { FADEALL_ANIMATION, FADE_ANIMATION, HORIPATHTWEEN_ANIMATION, HORIZONTALALL_ANIMATION, ONEBYONE_ANIMATION, POINTBYPOINT_ANIMATION, POINTTWEEN_ANIMATION, SIZINGRANDOM_ANIMATION, SIZING_ANIMATION, STROKETWEEN_ANIMATION, VERTICALALL_ANIMATION, VERTPATHTWEENALL_ANIMATION, VERTPATHTWEEN_ANIMATION } from '../../../core/animation-constants';
import { mathMax, mathRandom, mathRound } from '../../../core/zc-constants';
import { ORDINAL_DATATYPE } from '../../../core/datatype-constants';

export function setScatterBuilderConfig() {
    let _this = this,
        chart = this.chart,
        builderC = this.builderC,
        systemConf = chart.systemConf,
        rp = this.conf.params,
        seriesOptions = this.config.series,
        commonOptions = this.config.common,
        animationOptions = getAnimationConf(commonOptions, seriesOptions, this.chart, this.type),
        morphing = this.chart.systemConf.chart.plot.morph.enabled && this.chart.oldSeriesInfo;

    let animationType = animationOptions.type,
        easingType = animationOptions.easingType,
        transitionDuration = animationOptions.duration,
        duration = 0;

    const scatterOrBubble = this.commonOption.scatterOrBubble,
        currentseriesdata = this.data.data[0],
        subseriesIdx = currentseriesdata.subseriesIdx || 0, 
        noScatters = currentseriesdata.length,
        plotoptions = currentseriesdata.plotoptions;

    const { hasNegValue, xscale, yscale, axisrotated, stacked, yaxiscolumnorder, yrangePos } = builderC,
        datatypeX = chart.dataset.getDataType('x'),
        xCategories = datatypeX == ORDINAL_DATATYPE ? xscale.domain() : null,
        categories = datatypeX == ORDINAL_DATATYPE && xscale.domain != null && !defined(chart.dataObject.hierarchical)
            ? xCategories : chart.dataObject.getCategories('x');

    /*
    ENTER UPDATE EXIT TRANSITION DURATION
     */
    if (!scatterOrBubble) {
        animationType = (animationType == VERTPATHTWEEN_ANIMATION || animationType == VERTPATHTWEENALL_ANIMATION)
            ? VERTICALALL_ANIMATION
            : (animationType == HORIPATHTWEEN_ANIMATION) ? HORIZONTALALL_ANIMATION : animationType;
    } else {
        animationType = (animationType == FADEALL_ANIMATION) ? FADE_ANIMATION : animationType;
    }
    animationOptions.type = animationType;

    if (animationOptions.enabled) {
        if (morphing) {
            animationOptions._duration = this.chart.systemConf.chart.plot.morph.duration || animationOptions.duration;
        } else {
            if (animationType == POINTTWEEN_ANIMATION) {    // #ZC4674
                // duration = mathRound(transitionDuration / (categories.length - 1));
                duration = transitionDuration;
                animationOptions._intertween = function (ele) {
                    const serData = _this.seriesdataAfterUpdate[subseriesIdx],
                        len = serData.length,
                        baseData = Array.from({length: len}, () => serData[0]),
                        basedataShift = d3_values(baseData),
                        {getInitialX, getInitialY} = builderC,
                        layout = function (d) {
                            return {
                                transform: function (dt, i) {
                                    return `translate(${getInitialX(d[i])},${getInitialY(d[i])})`;
                                }
                            }
                        };

                    interTween(baseData, basedataShift, serData, categories, animationType, easingType, transitionDuration,
                        rp, layout, ele.selectAll('g.scatter'), 'scatter');
                }

            } else {
                duration = [POINTBYPOINT_ANIMATION, ONEBYONE_ANIMATION].includes(animationType) ? transitionDuration / noScatters : transitionDuration;
            }

            animationOptions._duration = duration;

            // add path duration and delay
            animationOptions._pathDuration = animationType === SIZINGRANDOM_ANIMATION ? (transitionDuration * 2) / 5
                : duration;
            animationOptions._pathDelay = animationType === SIZINGRANDOM_ANIMATION ?
                function () {
                    return mathRandom() * ((transitionDuration * 3) / 5);
                }
                : 0;
        }
    } else {
        animationOptions._duration = animationOptions._pathDuration = animationOptions._pathDelay = 0;
    }


    //* Add animation delay for enter, update and exit marks

    // animationOptions._enterdelay = function (d, i, ele) {
    //     const duration = [ONEBYONE_ANIMATION, POINTTWEEN_ANIMATION].includes(animationType) ?
    //         transitionDuration / noScatters : transitionDuration;
    //     return [ONEBYONE_ANIMATION, POINTTWEEN_ANIMATION].includes(animationType) ? i * duration : 0;
    // }

    animationOptions._delay = function (d, i, ele) {
        switch (animationType) {
            case POINTBYPOINT_ANIMATION:
                return ele[0] ? i * duration : 0;
            case POINTTWEEN_ANIMATION:
                return 0;
                // return this.previousElementSibling ? (i - 1) * duration : 0     // #ZC4674
            case ONEBYONE_ANIMATION:
                return i * duration;
            default:
                return 0;
        }
    };

    animationOptions._exitduration = 0;

    this.builderC.animationOptions = animationOptions;

    //* blink options
    this.builderC.blinkOptions = (plotoptions && plotoptions.animation && plotoptions.animation.blink
        ? mergeJSON(commonOptions.animation.blink, plotoptions.animation.blink, true)
        : commonOptions.animation.blink) || {};

    const renderingOrder = this.builderC.renderingOrder = this.conf.renderingOrderIndex();
    _this.builderC.stackIndex = _this.builderC.stacked ? ((chart.seriesdata.length * 2) + renderingOrder) : undefined;  // #ZC4648

    _this.builderC.yrangePos = this.oldRenderer.yrangePos();

    //* scatter renderer config
    const _getXYvalue = (d, type = 'x') => {
            const { xscale, yscale, zscale, axisrotated, stacked, yaxiscolumnorder, yrangePos } = builderC;
            return chart.dataObject.getXYvalue(axisrotated, stacked, xscale, yscale, yaxiscolumnorder, d, type, zscale, yrangePos)
        },
        xReversed = builderC.xReversed = systemConf.chart.axes.xaxis.reversed,
        yReversed = builderC.yReversed = systemConf.chart.axes.yaxis[yaxiscolumnorder].reversed,
        isPolar = chart.dataObject.isPolarAxisCategory;

    builderC._getXYvalue = _getXYvalue;

    builderC.getInitialX = function getInitialX(d) {
        switch (animationType) {
            case VERTICALALL_ANIMATION:
                if (axisrotated) {
                    const baseX = hasNegValue != null && yscale(hasNegValue) != null ?
                        yscale(mathMax(hasNegValue, yscale.domain()[0])) : yscale.origRange[0];
                    return baseX;
                } else {
                    return _getXYvalue(d, 'x');
                }
            case HORIZONTALALL_ANIMATION:
                if (axisrotated) {
                    return _getXYvalue(d, 'x');
                } else {
                    const baseX = (hasNegValue != null && xscale(hasNegValue) != null
                        ? xscale(mathMax(hasNegValue, xscale.domain()[0]))
                        : xscale.origRange[0]) + (xscale.bandwidth != null ? xscale.bandwidth() / 2 : 0);
                    return baseX;
                }
            case FADE_ANIMATION:
            case SIZING_ANIMATION:
            case SIZINGRANDOM_ANIMATION:
            case POINTTWEEN_ANIMATION:
            case POINTBYPOINT_ANIMATION:
            case STROKETWEEN_ANIMATION:
                return _getXYvalue(d, 'x');
            default:
                const range = (axisrotated ? yscale : xscale).origRange;
                const pos = (axisrotated && yReversed) || (!axisrotated && xReversed) ? range.length - 1 : 0;
                return range[pos];
        }
    }

    builderC.getInitialY = function getInitialY(d) {
        switch (animationType) {
            case VERTICALALL_ANIMATION:
                if (axisrotated) {
                    return _getXYvalue(d, 'y');
                } else {
                    const baseY = hasNegValue != null && yscale(hasNegValue) != null ?
                        yscale(mathMax(hasNegValue, yscale.domain()[0])) : yscale.origRange[0];
                    return baseY;
                }
            case HORIZONTALALL_ANIMATION:
                if (axisrotated) {
                    const baseY = (hasNegValue != null && xscale(hasNegValue) != null ?
                        xscale(mathMax(hasNegValue, xscale.domain()[0]))
                        : xscale.origRange[0]) + (xscale.bandwidth != null ? xscale.bandwidth() / 2 : 0);
                    return baseY
                } else {
                    return _getXYvalue(d, 'y');
                }
            case FADE_ANIMATION:
            case SIZING_ANIMATION:
            case SIZINGRANDOM_ANIMATION:
            case STROKETWEEN_ANIMATION:
            case POINTTWEEN_ANIMATION:
                return _getXYvalue(d, 'y');
            case POINTBYPOINT_ANIMATION:
                const arr = [];
                const yindex = chart.dataset.yidx(yaxiscolumnorder);
                const baseIdx = (isPolar && yReversed && !stacked) ? yscale.domain().length - 1 : 0;
                const baseY = !isPolar && hasNegValue != null && yscale(hasNegValue) != null
                    ? mathMax(hasNegValue, yscale.domain()[0])
                    : yscale.domain()[baseIdx];
                if (stacked) {
                    arr.y = 0;
                    arr.y0 = baseY
                }
                arr[yindex] = baseY;
                return _getXYvalue(arr, 'y')

            default:
                const range = (axisrotated ? xscale : yscale).origRange;
                const pos = (axisrotated && xReversed) || (!axisrotated && yReversed) ? range.length - 1 : 0;
                return range[pos];
        }
    }
}
